    c = 1.0
    d = 1.0 - qab * x / qap
    if abs(d) < FPMIN:
        d = FPMIN
    d = 1.0 / d
    h = d
    for m in range(1, MAXIT + 1):
        m2 = 2 * m
        aa = m * (b - m) * x / ((qam + m2) * (a + m2))
        d = 1.0 + aa * d
        if abs(d) < FPMIN:
            d = FPMIN
        c = 1.0 + aa / c
        if abs(c) < FPMIN:
            c = FPMIN
        d = 1.0 / d
        h *= d * c
        aa = -(a + m) * (qab + m) * x / ((a + m2) * (qap + m2))
        d = 1.0 + aa * d
        if abs(d) < FPMIN:
            d = FPMIN
        c = 1.0 + aa / c
        if abs(c) < FPMIN:
            c = FPMIN
        d = 1.0 / d
        delta = d * c
        h *= delta
        if abs(delta - 1.0) < CF_EPS:
            break
    return h


def _betai(a, b, x):
    """Regularized incomplete beta I_x(a, b) via lgamma + the betacf continued fraction."""
    if x <= 0.0:
        return 0.0
    if x >= 1.0:
        return 1.0
    bt = math.exp(
        math.lgamma(a + b) - math.lgamma(a) - math.lgamma(b)
        + a * math.log(x) + b * math.log(1.0 - x)
    )
    if x < (a + 1.0) / (a + b + 2.0):
        return bt * _betacf(a, b, x) / a
    return 1.0 - bt * _betacf(b, a, 1.0 - x) / b


def _gammq(a, x):
    """Regularized upper incomplete gamma Q(a, x): series for P then Q=1-P below x<a+1,
    continued fraction for Q above. (Numerical Recipes gammp/gammq.)"""
    if x < 0.0 or a <= 0.0:
        raise ValueError("bad args to _gammq")
    if x == 0.0:
        return 1.0
    gln = math.lgamma(a)
    if x < a + 1.0:
        ap = a
        s = 1.0 / a
        delta = s
        for _ in range(1000):
            ap += 1.0
            delta *= x / ap
            s += delta
            if abs(delta) < abs(s) * 3.0e-15:
                break
        p = s * math.exp(-x + a * math.log(x) - gln)
        return 1.0 - p
    FPMIN = 1.0e-300
    b = x + 1.0 - a
    c = 1.0 / FPMIN
    d = 1.0 / b
    h = d
    for i in range(1, 1000):
        an = -i * (i - a)
        b += 2.0
        d = an * d + b
        if abs(d) < FPMIN:
            d = FPMIN
        c = b + an / c
        if abs(c) < FPMIN:
            c = FPMIN
        d = 1.0 / d
        delta = d * c
        h *= delta
        if abs(delta - 1.0) < 3.0e-15:
            break
    return math.exp(-x + a * math.log(x) - gln) * h


def _p_two_tailed(test, statistic, df, df1, df2):
    """Two-tailed p-value for a reported test statistic. Pure stdlib math.

    Returns None when the inputs are out of the distribution's domain (so the caller
    abstains rather than inventing a verdict, DESIGN §3.4).
    """
    if test == "z":
        return 2.0 * (1.0 - 0.5 * (1.0 + math.erf(abs(statistic) / math.sqrt(2.0))))
    if test == "t":
        if df is None or df <= 0:
            return None
        x = df / (df + statistic * statistic)
        return _betai(df / 2.0, 0.5, x)
    if test == "r":
        if df is None or df <= 0:
            return None
        if abs(statistic) >= 1.0:
            return None  # r out of (-1, 1): t-transform is undefined
        t = statistic * math.sqrt(df / (1.0 - statistic * statistic))
        x = df / (df + t * t)
        return _betai(df / 2.0, 0.5, x)
    if test == "chi2":
        if df is None or df <= 0 or statistic < 0:
            return None
        return _gammq(df / 2.0, statistic / 2.0)
    if test == "F":
        if df1 is None or df2 is None or df1 <= 0 or df2 <= 0 or statistic < 0:
            return None
        x = df2 / (df2 + df1 * statistic)
        return _betai(df2 / 2.0, df1 / 2.0, x)
    return None

TEST = 't'
STATISTIC = 3.6
DF = 41
DF1 = None
DF2 = None
REPORTED_P = 0.013
DECIMALS = 3
EPS = 1e-9


def _round_p(p):
    return round(p, 6)


def _fmt_num(value):
    if isinstance(value, bool):
        value = int(value)
    if isinstance(value, int):
        return str(value)
    if isinstance(value, float) and value.is_integer():
        return str(int(value))
    return repr(value)


def _df_field():
    if TEST == 'F':
        return 'df1=' + _fmt_num(DF1) + ',df2=' + _fmt_num(DF2)
    return 'df=' + _fmt_num(DF)


p = _p_two_tailed(TEST, STATISTIC, DF, DF1, DF2)
threshold = 0.5 * 10 ** (-DECIMALS) + EPS
if p is not None and abs(REPORTED_P - p) > threshold:
    print(
        'INCONSISTENT test=' + TEST + ' stat=' + _fmt_num(STATISTIC) + ' '
        + _df_field() + ' reported_p=' + _fmt_num(REPORTED_P)
        + ' recomputed_p=' + _fmt_num(_round_p(p))
    )
else:
    print('OK')
